#include <iostream>
#include <string>
#include <string_view>

class Account
{
public:
    virtual ~Account() = default;
    std::string_view kind() const { return "account"; }
    virtual int rate() const { return 1; }
};

class Savings : public Account
{
public:
    std::string_view kind() const { return "savings"; }
    int rate() const override { return 5; }
};

class Checking : public Account
{
public:
    std::string_view kind() const { return "checking"; }
    int rate() const override { return 2; }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        if (type == "savings")
        {
            Savings obj{};
            const Account& ref{obj};
            std::cout << "Kind: " << ref.kind() << '\n';
            std::cout << "Rate: " << ref.rate() << '\n';
        }
        else
        {
            Checking obj{};
            const Account& ref{obj};
            std::cout << "Kind: " << ref.kind() << '\n';
            std::cout << "Rate: " << ref.rate() << '\n';
        }
    }

    return 0;
}

