#include <iostream>
#include <string>
#include <string_view>
#include <vector>

class LogEntry
{
public:
    virtual ~LogEntry() = default;
    std::string_view severity() const { return "INFO"; }
    virtual std::string_view text() const { return "generic"; }
    void render() const
    {
        std::cout << severity() << ": " << text() << '\n';
    }
};

class Warning : public LogEntry
{
public:
    std::string_view severity() const { return "WARN"; }
    std::string_view text() const override { return "warning"; }
};

class Error : public LogEntry
{
public:
    std::string_view severity() const { return "ERR"; }
    std::string_view text() const override { return "error"; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<LogEntry*> entries{};
    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        if (type == "warning")
            entries.push_back(new Warning{});
        else
            entries.push_back(new Error{});
    }

    for (const auto* e : entries)
        e->render();

    for (auto* e : entries)
        delete e;

    return 0;
}
